        "Delete (y/N)?".to_string()
    };

    let lines: Vec<Line> = prompt
        .lines()
        .map(|l| Line::from(l))
        .chain(std::iter::once(Line::raw("")))
        .collect();

    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);
