#[cfg(test)]
mod tests {
    use super::*;
    use crossterm::event::{KeyCode, KeyModifiers};

    fn key(c: char) -> KeyEvent {
        KeyEvent {
            code: KeyCode::Char(c),
            modifiers: KeyModifiers::NONE,
            kind: KeyEventKind::Press,
            state: event::KeyEventState::NONE,
        }
    }

    fn key_code(code: KeyCode) -> KeyEvent {
        KeyEvent {
            code,
            modifiers: KeyModifiers::NONE,
            kind: KeyEventKind::Press,
            state: event::KeyEventState::NONE,
        }
    }

    // ── Normal mode ──────────────────────────────────────────────────────

    #[test]
    fn normal_quit() {
        assert_eq!(handle_input(key('q'), Mode::Normal), Action::Quit);
    }

    #[test]
    fn normal_prev_column() {
        assert_eq!(
            handle_input(key('h'), Mode::Normal),
            Action::NavigatePrevColumn
        );
    }

    #[test]
    fn normal_next_column() {
        assert_eq!(
            handle_input(key('l'), Mode::Normal),
            Action::NavigateNextColumn
        );
    }

    #[test]
    fn normal_next_task() {
        assert_eq!(
            handle_input(key('j'), Mode::Normal),
            Action::NavigateNextTask
        );
    }

    #[test]
    fn normal_prev_task() {
        assert_eq!(
            handle_input(key('k'), Mode::Normal),
            Action::NavigatePrevTask
