    // ── Confirm mode ─────────────────────────────────────────────────────

    #[test]
    fn confirm_yes() {
        assert_eq!(handle_input(key('y'), Mode::Confirm, None), Action::ConfirmYes);
        assert_eq!(handle_input(key('Y'), Mode::Confirm, None), Action::ConfirmYes);
    }

    #[test]
    fn confirm_no() {
